<script>
(function(){
  var c=document.getElementById('c'),ctx=c.getContext('2d'),W,H,s=[];
  function rs(){W=c.width=window.innerWidth;H=c.height=window.innerHeight;}
  function mk(){s=[];for(var i=0;i<110;i++)s.push({x:Math.random()*W,y:Math.random()*H,r:Math.random()*1.1+0.2,a:Math.random(),da:(Math.random()-0.5)*0.007,col:Math.random()>0.65?'rgba(125,211,252,':'rgba(255,255,255,'});}
  function dr(){ctx.clearRect(0,0,W,H);s.forEach(function(p){p.a+=p.da;if(p.a<=0||p.a>=1)p.da*=-1;ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,Math.PI*2);ctx.fillStyle=p.col+p.a+')';ctx.fill();});requestAnimationFrame(dr);}
  rs();mk();dr();
  window.addEventListener('resize',function(){rs();mk();});
})();

function go(t){try{tavo.input.set(t);tavo.input.send();}catch(e){}}

var CARDS={
  xiushu: '',
  generator: '',
  visual: ''
};

var USAGE={
  xiushu: '【修书人已导入 ✓】\n\n在「角色」列表里找到「修书人」，点击进入对话。\n\n告诉它你想修改哪张角色卡，它会引导你完成操作。',
  generator: '【角色生成器 2.0 已导入 ✓】\n\n在「角色」列表里找到「角色生成器 2.0」，点击进入对话。\n\n按提示填写角色设定，它会生成完整的角色卡 JSON，可直接导入 Tavo 使用。',
  visual: '【视觉美化工坊已导入 ✓】\n\n在「角色」列表里找到「视觉美化工坊」，点击进入对话。\n\n选择你喜欢的界面风格，它会生成对应的正则脚本，导入后即可让聊天气泡焕然一新。'
};

async function importCard(key, btn) {
  var tag = document.getElementById('tag-' + key);
  btn.disabled = true;
  tag.textContent = '导入中…';
  try {
    var bytes = Uint8Array.from(atob(CARDS[key]), function(c){ return c.charCodeAt(0); });
    var raw = new TextDecoder('utf-8').decode(bytes);
    var card = JSON.parse(raw);
    var result = await tavo.character.import(card);
    if (result && result.characterId) {
      tag.textContent = '已导入 ✓';
      tag.style.background = 'rgba(45,212,191,0.15)';
      tag.style.color = '#2dd4bf';
      tag.style.borderColor = 'rgba(45,212,191,0.3)';
      tavo.input.set(USAGE[key]);
      tavo.input.send();
    } else {
      tag.textContent = '已取消';
      btn.disabled = false;
      setTimeout(function(){ tag.textContent = '一键导入'; }, 2000);
    }
  } catch(e) {
    tag.textContent = '导入失败';
    tag.style.color = '#fb7185';
    btn.disabled = false;
    setTimeout(function(){ tag.textContent = '一键导入'; tag.style.color = ''; }, 2500);
  }
}
</script>
